          </div>
          <div style={{ marginBottom: 16 }}>
            <div style={{ fontSize: 12, color: '#64748b', marginBottom: 4 }}>Paid Bills</div>
            <div style={{ fontSize: 20, fontWeight: 700 }}>{stats?.totalNotices || 0}</div>
