          <div>
            <div style={{ fontSize: 12, color: '#64748b', marginBottom: 4 }}>Pending Bills</div>
            <div style={{ fontSize: 20, fontWeight: 700 }}>{stats?.pendingBills || 0}</div>
          </div>
        </div>
      </Card>
